SELECT MAX(max_intensity) AS max_intensity_value
FROM peak_intensity
WHERE peak_id = 0;

SELECT signal_to_noise_ratio
FROM peak_intensity
WHERE max_intensity > 500;

SELECT AVG(max_intensity) AS average_max_intensity
FROM peak_intensity
WHERE peak_id = 1;

SELECT peak_id, max_intensity
FROM peak_intensity
ORDER BY max_intensity DESC;

SELECT scan_setting_id, COUNT(peak_id) AS num_peaks
FROM peak_data
GROUP BY scan_setting_id;

SELECT peak_id
FROM peak_intensity
WHERE max_intensity = (SELECT MAX(max_intensity) FROM peak_intensity);
